// ADR-0038, Wave 3 §3.2 — pre-Telegram step that builds a stable
// `alertId` keyed on (failed_workflow_id, error_signature) so each
// failure class produces exactly one ack-row per 30-min cooldown
// window (WF-98's SQL cooldown already filters at this granularity).
//
// WF-98 has no errorWorkflow set, so the chained POST /alerts/post
// failing cannot loop back here.
const err = $('Error Trigger').first()?.json ?? {};
const inserted = $('Insert n8n failure event').first()?.json ?? {};
const erroredWorkflowId = err.workflow?.id || 'unknown';
const erroredWorkflowName = err.workflow?.name || 'unknown';
const erroredExecutionId = err.execution?.id || 'unknown';
const lastNode = err.execution?.lastNodeExecuted || 'unknown';
const errorMessage = err.execution?.error?.message || err.error?.message || 'unknown error';
const errorSignature = inserted.error_signature || 'no-signature';
const alertId = `wf98:${erroredWorkflowId}:${errorSignature}`;
const summary = `n8n workflow failed — ${erroredWorkflowName} @ ${lastNode}: ${errorMessage}`;
return [{
  json: {
    alertId,
    summary,
    metadata: {
      workflowId: $workflow.id || 'unknown',
      executionId: $execution.id || 'unknown',
      erroredWorkflowId,
      erroredWorkflowName,
      erroredExecutionId,
      lastNode,
      errorMessage,
      errorSignature,
      failureEventId: inserted.id ?? null,
    },
  },
}];
